import math

class LanguageDetector:
    def __init__(self, profiles: dict[str, str], n: int = 3):
        # profiles: {"english": "sample english text...", "french": "texte français..."}
        self.n = n
        self.profiles = {}
        for lang, sample in profiles.items():
            self.profiles[lang] = self.char_ngrams(sample)

    def char_ngrams(self, text: str) -> dict:
        # Return frequency dict of character n-grams (lowercase)
        text = text.lower()
        ngrams = {}
        for i in range(len(text) - self.n + 1):
            gram = text[i:i + self.n]
            ngrams[gram] = ngrams.get(gram, 0) + 1
        return ngrams

    def cosine_similarity(self, vec_a: dict, vec_b: dict) -> float:
        shared = set(vec_a) & set(vec_b)
        dot = sum(vec_a[w] * vec_b[w] for w in shared)
        mag_a = math.sqrt(sum(v**2 for v in vec_a.values()))
        mag_b = math.sqrt(sum(v**2 for v in vec_b.values()))
        if mag_a == 0 or mag_b == 0:
            return 0.0
        return dot / (mag_a * mag_b)

